	@Check
	public void checkBuiltinFunctionArgumentTypes(MethodCall methodCall) {
	    String name = methodCall.getName();

	    if (name == null || name.isBlank()) {
	        return;
	    }

	    FunctionSignature signature =
	            Methods.standardRegistry().getSignature(name);

	    if (signature == null) {
	        return;
	    }

	    ValidatorTypeContext context = new ValidatorTypeContext();

	    for (int i = 0; i < methodCall.getArgs().size(); i++) {
	        Optional<SephirahType> expectedType = signature.getParameterType(i);

	        if (expectedType.isEmpty()) {
	            continue;
	        }

	        SephirahType actualType = inferType(methodCall.getArgs().get(i),
	        		context);

	        if (actualType == SephirahType.UNKNOWN) {
	            continue;
	        }

	        if (actualType != expectedType.get()) {
	            error("Function " + name + " argument " + (i + 1)
	                    + " expects " + displayType(expectedType.get())
	                    + ", but got " + displayType(actualType) + ".",
	                    methodCall,
	                    SephirahPackage.Literals.METHOD_CALL__ARGS,
	                    i,
	                    TYPE_MISMATCH);
	        }
	    }
	}
	
	@Check
	public void checkBuiltinFunctionConflict(Definition definition) {
		String name = definition.getName();
		
		if(name == null || name.isBlank()) {
			return;
		}
		
		if (Methods.previewRegistry().contains(name) || Methods.standardRegistry().contains(name)) {
	        error("Function name " + name + " conflicts with a built-in function.",
	                SephirahPackage.Literals.DEFINITION__NAME,
	                BUILTIN_FUNCTION_CONFLICT,
	                name);
	    }
	}
	
	@Check
	public void checkCyclicalFunctionReference(Definition definition) {
		FormulaModel model = EcoreUtil2.getContainerOfType(definition, FormulaModel.class);
		
		if(model == null) {
			return;
		}
		
		String name = definition.getName();
		
		if(name == null || name.isBlank()) {
			return;
		}
		
		try {
			checkFunctionCycle(model, name, new ArrayDeque<>());
		} catch (IllegalStateException exception) {
	        error(exception.getMessage(),
	                SephirahPackage.Literals.DEFINITION__NAME,
	                CYCLICAL_FUNCTION,
	                name);
	    }
	}
	
	@Check
	public void checkCyclicalVariableReference(VariableAssignment assignment) {
		FormulaModel model = EcoreUtil2.getContainerOfType(assignment, FormulaModel.class);
		
		if(model == null || assignment.getName() == null || assignment.getValue() == null) {
			return;
		}
		
		try {
			ModuleValueResolver resolver = new ModuleValueResolver(model, 
					Methods.previewRegistry());
			
			resolver.resolveValue(assignment.getName());
		} catch(IllegalStateException exception) {
			error(exception.getMessage(),
					SephirahPackage.Literals.ASSIGNMENT__NAME,
					CYCLICAL_REFERENCE,
					assignment.getName()
					);
		} catch(RuntimeException exception) {
			
			String cycleMessage = findVariableCycleMessage(exception);
			
			if(cycleMessage != null) {
				error(exception.getMessage(),
						SephirahPackage.Literals.ASSIGNMENT__NAME,
						CYCLICAL_REFERENCE,
						assignment.getName()
						);
			}
			
			return;
		}
	}
	
	@Check
	public void checkDefinitionVariablesUsed(Definition def) {
		EList<Assignment> args = def.getArgs();
		Expression expr = def.getExpr();

		if (expr == null) {
			return;
		}

		for (Assignment arg : args) {
			if (arg instanceof DefinitionVariable) {
				DefinitionVariable definitionVariable = (DefinitionVariable) arg;
				String varName = definitionVariable.getName();

				if (varName == null || varName.isBlank()) {
					continue;
				}

				if (!expressionContainsVariableName(expr, varName)) {
					warning("Declared variable has not been used: " + varName,
							SephirahPackage.Literals.DEFINITION__ARGS,
							args.indexOf(arg),
							UNUSED_VARIABLE,
							varName);
				}
			}
		}
	}
	
	@Check
	public void checkDivByZero(Divide div) {
		BigDecimal divisor = tryComputeStatic(div.getRight());

		if (divisor == null) {
			return;
		}

		if (BigDecimal.ZERO.compareTo(divisor) == 0) {
			error("Cannot divide by zero.", SephirahPackage.Literals.DIVIDE__RIGHT);
		}
	}
	
	@Check
	public void checkDuplicateFunctions(Definition definition) {
		FormulaModel model = EcoreUtil2.getContainerOfType(definition, FormulaModel.class);
		
		if(model == null) {
			return;
		}
		
		String name = definition.getName();
		
		if(name == null || name.isBlank()) {
			return;
		}
		
		boolean foundFirst = false;
		
		for(Definition other : model.getMethodDefs()) {
			if(!name.equals(other.getName())) {
				continue;
			}
			
			if(!foundFirst) {
				foundFirst = true;
				continue;
			}
			
			if (other == definition) {
	            error("Function name " + name + " cannot be declared more than once.",
	                    SephirahPackage.Literals.DEFINITION__NAME,
	                    DUPLICATE_FUNCTION,
	                    name);
	            return;
	        }
		}
	}
	
	@Check
	public void checkDuplicateParameters(Definition definition) {
		EList<Assignment> parameters = definition.getArgs();
		
		Set<String> seenNames = new HashSet<>();
		
		for(int i = 0; i < parameters.size(); i++) {
			Assignment parameter = parameters.get(i);
			String name = parameter.getName();
			
			if(name == null || name.isBlank()) {
				continue;
			}
			
			if(!seenNames.add(name)) {
				error("Parameter name " + name + " cannot be used more than once.",
	                    SephirahPackage.Literals.DEFINITION__ARGS,
	                    i,
	                    DUPLICATE_PARAMETER,
	                    name);
	            return;
			}
		}
	}
	
