	@Check
	public void checkExistingVariable(Variable var) {
		String name = var.getName();

		if (name == null || name.isBlank()) {
			error("Variable has no name.",
					SephirahPackage.Literals.VARIABLE__NAME,
					UNDECLARED_VARIABLE);
			return;
		}

		/*
		 * Qualified names are reserved for runtime/host-object paths for now:
		 *
		 *   self.strength
		 *   weapon.damage
		 *   target.armorClass
		 *
		 * These should not be forced to resolve as module-local variables.
		 */
		if (name.contains(".")) {
			return;
		}

		if (isVariableDeclared(var, name)) {
			return;
		}

		error("Variable has not been declared: " + name,
				SephirahPackage.Literals.VARIABLE__NAME,
				UNDECLARED_VARIABLE,
				name);
	}
	
	@Check
	public void checkFunctionArity(MethodCall methodCall) {
		String name = methodCall.getName();
		
		if(name == null || name.isBlank()) {
			return;
		}
		
		FunctionSignature signature = getFunctionSignature(methodCall, name);
		
		if(signature == null) {
			return;
		}
	    
		int actual = methodCall.getArgs().size();
		
		if(signature.accepts(actual)) {
			return;
		}
		
	    error(signature.describeMismatch(name, actual),
        SephirahPackage.Literals.METHOD_CALL__NAME,
        FUNCTION_ARITY,
        name,
        String.valueOf(actual));
	}
	
	@Check
	public void checkFunctionCallBodyTypes(MethodCall methodCall) {
	    String name = methodCall.getName();

	    if (name == null || name.isBlank()) {
	        return;
	    }

	    FormulaModel model = EcoreUtil2.getContainerOfType(methodCall, FormulaModel.class);

	    if (model == null) {
	        return;
	    }

	    Definition definition = findDefinition(model, name);

	    if (definition == null || definition.getExpr() == null) {
	        return;
	    }

	    if (definition.getArgs().size() != methodCall.getArgs().size()) {
	        return;
	    }

	    ValidatorTypeContext context = new ValidatorTypeContext();

	    Map<String, SephirahType> parameterTypes = new HashMap<>();
	    Map<String, ParameterBinding> parameterBindings = new HashMap<>();

	    for (int i = 0; i < definition.getArgs().size(); i++) {
	        Assignment parameter = definition.getArgs().get(i);
	        Expression argument = methodCall.getArgs().get(i);

	        String parameterName = parameter.getName();

	        if (parameterName == null || parameterName.isBlank()) {
	            continue;
	        }

	        SephirahType argumentType = inferType(argument,
	        		context);
	        
	        parameterTypes.put(parameterName, argumentType);
	        parameterBindings.put(parameterName,
	        		new ParameterBinding(methodCall, i, parameterName));
	    }

	    context.inferenceContext.pushLocalVariableTypes(parameterTypes);
	    context.localParameterBindings.push(parameterBindings);

	    try {
	        checkExpressionTypesInContext(definition.getExpr(), context);
	    } finally {
	        context.inferenceContext.popLocalVariableTypes();
	        context.localParameterBindings.pop();
	    }
	}

